(async () => {
  const app = new PIXI.Application({ width: window.innerWidth, height: window.innerHeight, backgroundColor: 0x0a0a0a, antialias: true });
  document.body.appendChild(app.view);
  document.getElementById('loading').style.display = 'none';
  window.addEventListener('resize', () => { app.renderer.resize(window.innerWidth, window.innerHeight); });

  let score = 0;
  let entities = [];
  const W = app.screen.width, H = app.screen.height;

  const grid = new PIXI.Graphics();
  grid.lineStyle(1, 0x111111);
  for (let x = 0; x < W; x += 40) grid.moveTo(x, 0).lineTo(x, H);
  for (let y = 0; y < H; y += 40) grid.moveTo(0, y).lineTo(W, y);
  app.stage.addChild(grid);

  function spawnEntity(x, y) {
    const g = new PIXI.Graphics();
    const size = 20 + Math.random() * 20;
    const colors = [0x00c8ff, 0xd4af37, 0xff4444, 0x44ff44, 0x9966ff, 0xff6600];
    const color = colors[Math.floor(Math.random() * colors.length)];
    g.beginFill(color, 0.8).drawRoundedRect(-size/2, -size/2, size, size, 4).endFill();
    g.x = x; g.y = y;
    g.vx = (Math.random() - 0.5) * 2;
    g.vy = (Math.random() - 0.5) * 2;
    g.interactive = true; g.cursor = 'pointer';
    g.on('pointerdown', () => { score += 100; document.getElementById('score').textContent = score; g.alpha = 0.3; setTimeout(() => { g.alpha = 0.8; }, 300); });
    app.stage.addChild(g); entities.push(g);
  }

  for (let i = 0; i < 16; i++) spawnEntity(Math.random()*W*0.7+W*0.15, Math.random()*H*0.7+H*0.15);

  app.ticker.add(() => {
    entities.forEach(e => {
      e.x += e.vx; e.y += e.vy;
      if (e.x < 20 || e.x > W-20) e.vx *= -1;
      if (e.y < 20 || e.y > H-20) e.vy *= -1;
      e.rotation += 0.005;
    });
  });

  console.log('[SLA113] Game initialized');
})();
